1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean; enchantment?: number };
12	type Step = { type: string; items: Item[] };
13	
14	const BLOCK_OF_3_PRICE = 60;
15	
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	function countByType(items: Item[]): Record<string, number> {
19	  const counts: Record<string, number> = {};
20	  for (const item of items) {
21	    counts[item.type] = (counts[item.type] ?? 0) + 1;
22	  }
23	  return counts;
24	}
25	
26	function priceForType(type: string, count: number): number {
27	  if (COMPONENT_TYPES.includes(type) && count === 3) {
28	    return BLOCK_OF_3_PRICE;
29	  }
30	  return count * BASE_PREMIUM_BY_TYPE[type];
31	}
32	
33	function isHighlyEnchanted(item: Item): boolean {
34	  return (item.enchantment ?? 0) >= 5;
35	}
36	
37	function hasItemModifier(item: Item): boolean {
38	  return Boolean(item.cursed) || isHighlyEnchanted(item);
39	}
40	
41	const CURSE_SURCHARGE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
43	
44	function itemPremium(item: Item): number {
45	  const base = BASE_PREMIUM_BY_TYPE[item.type];
46	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
47	  const enchantmentSurcharge = isHighlyEnchanted(item)
48	    ? base * HIGH_ENCHANTMENT_SURCHARGE
49	    : 0;
50	  return base + curseSurcharge + enchantmentSurcharge;
51	}
52	
53	function modifiedPremium(items: Item[]): number {
54	  return items
55	    .filter(hasItemModifier)
56	    .reduce((total, item) => total + itemPremium(item), 0);
57	}
58	
59	function plainPremium(items: Item[]): number {
60	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
61	  return Object.entries(counts).reduce(
62	    (total, [type, count]) => total + priceForType(type, count),
63	    0,
64	  );
65	}
66	
67	function basePremium(items: Item[]): number {
68	  return modifiedPremium(items) + plainPremium(items);
69	}
70	
71	export function runScenario(steps: Step[]): unknown[] {
72	  return steps.map((step) => ({
73	    premium: PROCESSING_FEE + basePremium(step.items),
74	  }));
75	}
